n = int(input())
sum = 0
ok = True

def f():
    try:
        line = input().strip()
        return int(line)
    except:
        global ok
        ok = False
        print(f'Error for data {line}! Reinput')
    return f()

for _ in range(n):
    sum += f()
if ok:
    print('All OK')
print(f'avg grade = {sum/n:.2f}')
